-- Migration file for creating projects table\nCREATE TABLE projects (\n    id SERIAL PRIMARY KEY,\n    name VARCHAR(255) NOT NULL,\n    description TEXT,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n    status project_status NOT NULL DEFAULT 'active'\n);\n\n-- Migration file for creating inspections table\nCREATE TABLE inspections (\n    id SERIAL PRIMARY KEY,\n    project_id INTEGER REFERENCES projects(id),\n    inspection_date TIMESTAMP NOT NULL,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n    status inspection_status NOT NULL DEFAULT 'pending'\n);\n\n-- Migration file for creating recommendations table\nCREATE TABLE recommendations (\n    id SERIAL PRIMARY KEY,\n    inspection_id INTEGER REFERENCES inspections(id),\n    recommendation_text TEXT NOT NULL,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n    status recommendation_status NOT NULL DEFAULT 'open'\n);\n\n-- Migration file for creating security management table\nCREATE TABLE security_management (\n    id SERIAL PRIMARY KEY,\n    project_id INTEGER REFERENCES projects(id),\n    security_measures TEXT NOT NULL,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP\n);\n\n-- Migration file for creating audit logs table\nCREATE TABLE audit_logs (\n    id SERIAL PRIMARY KEY,\n    action VARCHAR(255) NOT NULL,\n    user VARCHAR(255) NOT NULL,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP\n);\n\n-- Migration file for creating alerts table\nCREATE TABLE alerts (\n    id SERIAL PRIMARY KEY,\n    project_id INTEGER REFERENCES projects(id),\n    alert_message TEXT NOT NULL,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n    status alert_status NOT NULL DEFAULT 'unread'\n);\n\n-- Status Enums\nCREATE TYPE project_status AS ENUM ('active', 'archived', 'completed');\nCREATE TYPE inspection_status AS ENUM ('pending', 'completed', 'failed');\nCREATE TYPE recommendation_status AS ENUM ('open', 'closed');\nCREATE TYPE alert_status AS ENUM ('unread', 'read');\n\n-- Apply all migrations here\nBEGIN;\n    -- Call creation scripts here\n    -- CREATE TABLE ...\nCOMMIT;